using System.Collections.Generic;

public sealed class Filter
{
    public int Count(List<int> known, IEnumerable<int> input)
    {
        var lookup = new HashSet<int>(known);
        var hits = 0;
        foreach (var value in input)
        {
            if (lookup.Contains(value))
            {
                hits++;
            }
        }

        return hits;
    }
}
